values
('computer-science:1-3-1-networks-and-topologies:match:82d222e5', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Switch”?", "options": ["The maximum amount of data that can be transferred across a connection in a given time", "Every computer has equal status and can act as both client and server, with no dedicated central machine", "Connects multiple wired devices within the same LAN, forwarding data to the addressed device only", "A network spanning a large geographical area, such as multiple cities or countries"]}'::jsonb, '{"answer": 2, "explain": "“Switch” means: Connects multiple wired devices within the same LAN, forwarding data to the addressed device only"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:37ac4864', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Router”?", "options": ["Hardware, built into or fitted inside a device, that lets it physically connect to a network", "Storing data or running services on remote servers accessed over the Internet, rather than locally", "Connects multiple wired devices within the same LAN, forwarding data to the addressed device only", "Connects one network to a different network, such as a LAN to the Internet"]}'::jsonb, '{"answer": 3, "explain": "“Router” means: Connects one network to a different network, such as a LAN to the Internet"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:a9b4a662', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “WAP”?", "options": ["Lets wireless devices join a wired LAN by converting between wired and wireless signals", "A network confined to a single site, such as one building or a small group of nearby buildings", "Connects one network to a different network, such as a LAN to the Internet", "Hardware, built into or fitted inside a device, that lets it physically connect to a network"]}'::jsonb, '{"answer": 0, "explain": "“WAP” means: Lets wireless devices join a wired LAN by converting between wired and wireless signals"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:6c63f401', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “DNS”?", "options": ["A network spanning a large geographical area, such as multiple cities or countries", "Provides shared services or resources that client computers request and use", "The system of servers that converts a URL into the matching IP address", "Lets wireless devices join a wired LAN by converting between wired and wireless signals"]}'::jsonb, '{"answer": 2, "explain": "“DNS” means: The system of servers that converts a URL into the matching IP address"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:8870c738', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “The cloud”?", "options": ["Connects one network to a different network, such as a LAN to the Internet", "Storing data or running services on remote servers accessed over the Internet, rather than locally", "Hardware, built into or fitted inside a device, that lets it physically connect to a network", "Requests and makes use of the services or resources a server provides"]}'::jsonb, '{"answer": 1, "explain": "“The cloud” means: Storing data or running services on remote servers accessed over the Internet, rather than locally"}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:exam:4d494f80', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'exam', 'mcq', 1, '{"num": "P1", "question": "<p>Northfield College''s computer lab has twenty desktop PCs that never move. Identify which cable type is most likely used to connect them to the network.</p>", "options": ["Twisted pair copper cable", "A wireless-only radio antenna cable", "An HDMI display cable", "A coaxial television aerial cable"], "caseStudy": "<p>Northfield College has a computer lab with twenty desktop PCs wired into the network, and a library where students and staff connect their own laptops and phones to the college''s encrypted Wi-Fi network.</p>", "hint": "Think about the cable type Ethernet connections normally use for fixed, wired devices."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Twisted pair copper cable</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The other options are either not genuine Ethernet cabling or are used for a completely different job.</li>\n</ul>\n</div>", "modelAnswer": "Twisted pair copper cable."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:exam:8b7d9caa', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'exam', 'mcq', 1, '{"num": "P2", "question": "<p>A member of staff at Northfield College pairs their wireless headphones directly with their phone. Identify which wireless technology is being used.</p>", "options": ["Bluetooth", "Wi-Fi, connecting through the college''s wireless access points", "Ethernet, using a short wireless-enabled cable", "Fibre-optic wireless transmission between the two devices"], "caseStudy": "<p>Northfield College has a computer lab with twenty desktop PCs wired into the network, and a library where students and staff connect their own laptops and phones to the college''s encrypted Wi-Fi network.</p>", "hint": "Think about which wireless technology creates a short-range connection directly between two nearby devices, without needing a WAP."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>Bluetooth</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Wi-Fi involves a wireless access point; the other two options describe technologies that don''t apply to this direct device-to-device pairing.</li>\n</ul>\n</div>", "modelAnswer": "Bluetooth."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:exam:136b4e3e', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'exam', 'mcq', 1, '{"num": "P3", "question": "<p>State which of these best defines what a protocol is on a computer network.</p>", "options": ["An agreed set of rules that allows devices to communicate with each other", "A physical cable that must be plugged into both devices before any data can be sent", "A password that a user types in before being allowed to join a wireless network", "A brand name that a manufacturer gives to one specific model of router or switch"], "hint": "Think about communication rules, not physical hardware, passwords or branding."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>An agreed set of rules that allows devices to communicate with each other</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>The other three options describe hardware, security or branding — none of which is what a protocol actually is.</li>\n</ul>\n</div>", "modelAnswer": "An agreed set of rules that allows devices to communicate with each other."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:exam:f2ed2267', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'exam', 'mcq', 1, '{"num": "P4", "question": "<p>A new scanner at Meadow Hospital is given the address 192.168.4.17 when it joins the hospital''s network. Identify which type of address this is.</p>", "options": ["An IPv4 address", "An IPv6 address", "A MAC address", "A protocol standard"], "caseStudy": "<p>Meadow Hospital''s IT department manages hundreds of devices — including monitors, scanners and record-keeping terminals — made by many different medical equipment manufacturers, all needing to communicate over the hospital''s network.</p>", "hint": "Count how many numbers there are, and check whether they are written in denary or hexadecimal."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>An IPv4 address</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Four denary numbers separated by dots is the IPv4 format; IPv6 uses eight hexadecimal groups, and a MAC address is written in hexadecimal pairs.</li>\n</ul>\n</div>", "modelAnswer": "An IPv4 address."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:ee150a95', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "Which type of cable is most commonly used for a wired Ethernet connection?", "options": ["Twisted pair copper cable", "A wireless-only radio antenna cable, since Ethernet never uses physical cabling", "An HDMI cable connecting a monitor to a computer", "A coaxial cable used for a television aerial signal"]}'::jsonb, '{"answer": 0, "explain": "Ethernet connections typically use twisted pair copper cable (fibre for some longer runs); the other options are used for completely different jobs or aren''t real Ethernet cabling."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:d8f79942', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "A shop''s Wi-Fi network is encrypted. What does this actually achieve?", "options": ["It stops anyone who intercepts the data from being able to read it, without stopping the interception itself", "It makes the wireless signal completely impossible for any other nearby device to ever detect, pick up or intercept in the first place", "It guarantees that only customers who ask staff for the Wi-Fi password can ever connect a device", "It automatically doubles the amount of bandwidth available to every connected device"]}'::jsonb, '{"answer": 0, "explain": "Encryption scrambles the data using a key. It doesn''t stop the signal being intercepted — it stops the intercepted data from being readable without that key."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:eac2993e', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "Which of these correctly describes an IP address?", "options": ["An address, assigned by the network, that identifies a device so that data reaches it correctly", "A fixed hardware code, burned into a network card, that never changes for the life of the device", "A password required before a device is allowed to join any wireless network", "A brand name given by a manufacturer to one specific model of router"]}'::jsonb, '{"answer": 0, "explain": "An IP address identifies a device and is assigned by the network — the second option actually describes a MAC address instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:1bd7df59', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "Why does an IPv6 address use a completely different format from an IPv4 address?", "options": ["IPv4''s denary format was running out of unique addresses, so IPv6 uses a far larger hexadecimal format", "IPv6 was designed purely to make network addresses shorter and much quicker for ordinary people to type out", "IPv4 addresses became too easy for hackers to guess correctly, so the format itself had to change", "IPv6 replaced IPv4''s format purely to remove the need for DNS to look up any address at all"]}'::jsonb, '{"answer": 0, "explain": "IPv4''s four-denary-number format only allows a limited number of unique addresses. IPv6''s eight-group hexadecimal format provides a vastly larger address space instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:5d421511', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "What is true about a device''s MAC address?", "options": ["It is burned into the network interface card by its manufacturer and stays fixed for the device''s life", "It is assigned freshly by whichever network the device happens to connect to, and can change between different networks", "It is chosen freely by the device''s user the first time a network connection is set up", "It only exists for wireless devices, since wired devices are identified by their IP address instead"]}'::jsonb, '{"answer": 0, "explain": "A MAC address is fixed by the manufacturer when the network interface card is made — it does not change when the device joins a different network."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:952c13ca', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "A technician says a device''s IP address can change, but its MAC address cannot. Why is this correct?", "options": ["The IP address is assigned by the network the device joins, while the MAC address is fixed by the manufacturer", "Both addresses are actually fixed completely permanently, so the technician''s statement here must be incorrect", "The MAC address only ever applies to a device''s very first network connection, then it changes", "IP addresses cannot change once a device has connected to any network for the very first time"]}'::jsonb, '{"answer": 0, "explain": "An IP address is assigned fresh by whichever network a device joins, so it can change. A MAC address is burned in at manufacture and never changes."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:37c907d1', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "Why do networks rely on agreed standards?", "options": ["So hardware and software made by different manufacturers can work together and communicate", "So that every network in the world must use hardware bought from one single manufacturer", "So that a network''s speed automatically increases each time a new standard is published", "So governments can charge a licence fee to any company wanting to sell networking hardware"]}'::jsonb, '{"answer": 0, "explain": "Standards are agreed specifications. Following them lets equipment from completely different manufacturers still communicate and work together successfully."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:1fe28eb7', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "What best defines a protocol?", "options": ["An agreed set of rules that governs how devices communicate with each other", "A physical device that connects multiple computers together within one office", "A password that must be entered before a device can join a network", "A brand name that one manufacturer gives to its own range of routers"]}'::jsonb, '{"answer": 0, "explain": "A protocol is a set of communication rules, not a physical device, a password, or a manufacturer''s brand name."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:28fa553b', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "What does TCP do to data before IP routes it across a network?", "options": ["Splits it into packets, then reassembles them in order and requests any lost or corrupted ones again", "Permanently deletes the original data from the sender''s device the moment it has finished being sent", "Converts the data into a completely different file format that any device on any network can open", "Physically boosts the strength of a wireless signal so that it is able to travel much further"]}'::jsonb, '{"answer": 0, "explain": "TCP''s role is splitting data into packets, reassembling them correctly at the destination, and checking for lost or corrupted packets to be resent."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:eb345eb0', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "A website lets customers pay for goods online. Which protocol should its checkout page use, and why?", "options": ["HTTPS, because it adds encryption to protect the customer''s payment data in transit", "FTP, because it was specifically designed to transfer card payment details securely between banks", "SMTP, because it is the protocol responsible for handling secure online payments", "HTTP, because encryption would only slow down how quickly the checkout page loads"]}'::jsonb, '{"answer": 0, "explain": "HTTPS does the same job as HTTP but adds encryption, protecting sensitive data such as payment details from being read if intercepted."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:4c2909ff', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "A user reads the same email account on their phone and their laptop, and every message stays in sync on both devices. Which protocol is most likely retrieving their mail?", "options": ["IMAP, because it keeps messages on the server and syncs them across every device", "POP, because it downloads a separate independent copy of each message to every device", "SMTP, because it is the protocol responsible for retrieving mail from a server", "HTTP, because it is used for retrieving any content stored on any kind of server"]}'::jsonb, '{"answer": 0, "explain": "IMAP keeps mail on the server and keeps every device''s view of the mailbox in sync — POP typically downloads and removes each message from the server instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:mcq:bcd1d855', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'mcq', 'mcq', 1, '{"question": "What is one genuine benefit of dividing a network''s protocols into layers?", "options": ["Each layer can be developed or changed independently without needing to redesign the other layers", "It removes the need for absolutely any device anywhere on the whole network to ever follow an agreed standard", "It means data no longer needs to travel through more than one single layer to be delivered", "It guarantees that a network''s overall bandwidth automatically increases every single year"]}'::jsonb, '{"answer": 0, "explain": "As long as a layer still does its job the same way, it can be updated or replaced on its own — that independence is one of layering''s core benefits."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:1f21b7c2', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "Bluetooth is designed to create a short-range connection directly between two nearby devices."}'::jsonb, '{"answer": true, "explain": "Correct — Bluetooth pairs two devices directly, without needing a wireless access point or router."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:41ba99b1', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "A wireless access point (WAP) lets wireless devices join the same LAN that wired devices are already connected to."}'::jsonb, '{"answer": true, "explain": "Correct — a WAP converts between wired and wireless signals, letting wireless devices join an existing LAN."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:8436c0c1', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "Encrypting a wireless network stops the data from being intercepted by anyone else."}'::jsonb, '{"answer": false, "explain": "Encryption does not stop interception — a wireless signal can still be picked up by any device in range. It makes the intercepted data unreadable without the correct key."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:b5df2691', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "An IPv4 address is written as four denary numbers separated by dots."}'::jsonb, '{"answer": true, "explain": "Correct — for example, 192.168.1.1. IPv6 addresses use eight groups of hexadecimal digits instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:eb376889', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "A device''s MAC address can change if the device is moved to a different network."}'::jsonb, '{"answer": false, "explain": "A MAC address is burned into the network interface card by its manufacturer and stays the same for the device''s whole life — it is the IP address that can change between networks."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:a6e0e2b8', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "TCP/IP is a single protocol, rather than a suite of protocols working together."}'::jsonb, '{"answer": false, "explain": "TCP/IP is a suite (collection) of protocols, including TCP and IP, which each do a different job."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:3f46a78e', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "POP typically removes an email from the server once it has been downloaded to a device."}'::jsonb, '{"answer": true, "explain": "Correct — this is the key difference from IMAP, which keeps email on the server and syncs it across devices instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tf:35a8452e', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tf', 'tf', 1, '{"question": "Dividing a network into layers makes it harder to update one part of the system without affecting the rest."}'::jsonb, '{"answer": false, "explain": "The opposite is true — layering means a layer can usually be updated or replaced on its own, without needing to redesign the other layers."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:ffafa9fa', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "What is Ethernet, and where is it used?", "reading": "<h4>Ethernet: the standard for wired networking</h4>\n<ul>\n<li><strong>Ethernet</strong> is the most widely used standard for connecting devices to a network using cables.</li>\n<li>Ethernet connections normally use <strong>twisted pair copper cable</strong> (fibre-optic cable is sometimes used instead for longer runs, such as a connection between two buildings).</li>\n<li>A device joins the network by plugging an Ethernet cable into its network port and into a switch (or a router with built-in switch ports).</li>\n</ul>\n<h4>Typical uses</h4>\n<ul>\n<li>Ethernet suits devices that stay in one place and need a fast, reliable connection — desktop PCs in a computer suite, servers, and network printers.</li>\n<li>Because the cable carries a dedicated signal straight to that one device, a wired Ethernet connection is not affected by the interference or distance problems that can weaken a wireless connection.</li>\n</ul>", "question": "Which of these is the most typical use for a wired Ethernet connection?", "options": ["A desktop PC that stays in one fixed place in a school computer suite", "A phone that a student carries around the building all day between lessons", "A laptop being used on a bench outside during an outdoor lesson", "A delivery driver''s handheld scanner being used out on their delivery round"]}'::jsonb, '{"answer": 0, "explain": "Ethernet is a wired standard, so it suits fixed devices that stay connected to one cable — not devices that need to move around freely."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:ab1113f6', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "How do Wi-Fi and Bluetooth differ?", "reading": "<h4>Wi-Fi — wireless access to a LAN</h4>\n<ul>\n<li><strong>Wi-Fi</strong> lets a device connect wirelessly to a LAN through a <strong>wireless access point (WAP)</strong>, doing the same job wirelessly that an Ethernet cable does for a wired device.</li>\n<li>A single WAP can normally serve many devices at once, and Wi-Fi typically covers a whole room, building or site.</li>\n</ul>\n<h4>Bluetooth — short-range device pairing</h4>\n<ul>\n<li><strong>Bluetooth</strong> creates a short-range wireless connection directly <em>between two nearby devices</em> — no WAP or router is involved at all.</li>\n<li>Typical examples: pairing wireless headphones to a phone, a wireless keyboard to a laptop, or a phone to a car''s speaker system.</li>\n<li>Bluetooth''s range is much shorter than Wi-Fi''s, and it is designed for a small number of devices connecting directly, not for joining a whole LAN.</li>\n</ul>", "question": "A student pairs their wireless earbuds directly with their phone, with no router or access point involved at all. Which technology is this?", "options": ["Bluetooth", "Wi-Fi, connecting through a wireless access point", "Ethernet, using a wireless-enabled cable", "A fibre-optic wireless connection"]}'::jsonb, '{"answer": 0, "explain": "Bluetooth creates a short-range connection directly between two nearby devices without needing a wireless access point — exactly what''s being described here."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:40ec6217', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "Wired vs wireless: weighing up the trade-offs", "reading": "<h4>Comparing wired and wireless connections</h4>\n<table>\n<tr><th>Factor</th><th>Wired (e.g. Ethernet)</th><th>Wireless (e.g. Wi-Fi)</th></tr>\n<tr><td>Speed</td><td>Generally faster and more consistent</td><td>Generally slower, and can vary</td></tr>\n<tr><td>Reliability / interference</td><td>Not affected by walls or radio interference</td><td>Can be weakened by walls, distance and other wireless signals</td></tr>\n<tr><td>Security</td><td>Harder to intercept — needs a physical connection to the cable</td><td>Signals travel through the air and can be intercepted by anyone in range</td></tr>\n<tr><td>Mobility</td><td>Device must stay near its cable</td><td>Device can move freely within range</td></tr>\n<tr><td>Cost / installation</td><td>Cabling can be expensive and disruptive to install in an existing building</td><td>Cheaper and quicker to set up, with no cabling needed</td></tr>\n</table>\n<h4>So which is \"better\"?</h4>\n<ul>\n<li>Neither is better in every situation. A fixed desktop PC in an office usually benefits from a wired connection''s speed and security, while a laptop or phone that needs to move around a building needs wireless.</li>\n<li>Most real networks use both: wired connections for fixed, high-demand devices, and wireless for mobile ones.</li>\n</ul>", "question": "Why is a wired connection generally considered more secure than an equivalent wireless connection?", "options": ["Intercepting it needs physical access to the cable, unlike a signal broadcast through the air", "Wired connections automatically encrypt every byte of data, while wireless connections never can", "Wireless signals are physically incapable of carrying any data that a hacker could want", "Wired connections cannot be used by more than one device at the same time"]}'::jsonb, '{"answer": 0, "explain": "A wired signal stays inside the cable, so intercepting it needs a physical connection to that cable. A wireless signal is broadcast through the air and can be picked up by any device in range."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:f8f319bb', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "How does encryption protect data sent wirelessly?", "reading": "<h4>What encryption actually does</h4>\n<ul>\n<li><strong>Encryption</strong> means scrambling data into an unreadable form, using a <strong>key</strong>, before it is sent.</li>\n<li>Only a device that has the correct key can unscramble (decrypt) the data back into its original, readable form.</li>\n</ul>\n<h4>Why wireless networks need it</h4>\n<ul>\n<li>Wireless signals travel through the air in every direction, so anyone within range — not just the intended recipient — can potentially pick up (intercept) the data being sent.</li>\n<li>A wired connection is much harder to intercept, since it would need a physical connection to the cable itself.</li>\n</ul>\n<h4>The key exam point</h4>\n<ul>\n<li>Encryption does <strong>NOT</strong> stop data from being intercepted — a nearby device can still pick up the encrypted signal travelling through the air.</li>\n<li>What encryption does is make any intercepted data <strong>unreadable and useless</strong> to whoever intercepted it, unless they also have the correct key.</li>\n</ul>", "question": "A hacker intercepts data being sent over an encrypted wireless network. What is actually true?", "options": ["They have the data, but cannot read it without the correct decryption key", "They cannot have intercepted it at all, since encryption blocks interception completely", "They can read it instantly, since encryption only hides who originally sent it", "Encryption stops the wireless signal from ever leaving the sending device"]}'::jsonb, '{"answer": 0, "explain": "Encryption doesn''t stop a wireless signal being intercepted — it just makes the intercepted data meaningless without the correct key to unscramble it."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:852f1185', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "What does an IP address identify?", "reading": "<h4>What an IP address is for</h4>\n<ul>\n<li>An <strong>IP address</strong> identifies a device on a network (and which network it belongs to), so that data sent across the network reaches the correct destination.</li>\n<li>Every device communicating over a network — including the Internet — needs an IP address.</li>\n</ul>\n<h4>IP addresses can change</h4>\n<ul>\n<li>Unlike some hardware identifiers, an IP address is <strong>assigned by the network</strong> the device is connected to, rather than being fixed permanently to the device itself.</li>\n<li>A device''s IP address can change — for example, if it connects to a different network, or if the same network assigns it a new address the next time it connects.</li>\n</ul>", "question": "Which statement correctly describes an IP address?", "options": ["It is assigned by the network a device connects to, and can change between connections", "It is a fixed hardware code that is burned into a device''s network card and never changes", "It is a password that must be entered before a device is allowed onto a wireless network", "It is a brand name given by a manufacturer to one specific model of router"]}'::jsonb, '{"answer": 0, "explain": "An IP address is assigned by whichever network a device joins, which is exactly why it can change — that description belongs to a MAC address instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:86888876', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "IPv4 vs IPv6 — two address formats", "reading": "<h4>IPv4</h4>\n<ul>\n<li>Written as four <strong>denary (decimal)</strong> numbers, each between 0 and 255, separated by dots — for example, 192.168.1.1.</li>\n<li>Each of the four numbers is called an <strong>octet</strong>.</li>\n</ul>\n<h4>IPv6</h4>\n<ul>\n<li>Written as eight groups of <strong>hexadecimal</strong> digits, separated by colons — for example, 2001:0db8:0000:0000:0000:ff00:0042:8329.</li>\n</ul>\n<h4>Why IPv6 exists</h4>\n<ul>\n<li>IPv4 only allows a limited number of unique addresses, and the huge growth in the number of devices connecting to the Internet meant the supply of available IPv4 addresses has been running out.</li>\n<li>IPv6 provides a vastly larger range of possible addresses, so there are enough unique addresses for every device that needs one, now and in future.</li>\n</ul>", "question": "Why was IPv6 introduced alongside IPv4?", "options": ["IPv4 only offers a limited number of unique addresses, and these were running out", "IPv4 addresses were found to be far too easily intercepted on wireless networks", "IPv6 exists purely to make addresses easier for people to memorise and type", "IPv4 stopped working correctly once mobile phones first connected to the Internet"]}'::jsonb, '{"answer": 0, "explain": "IPv4''s address space is limited, and the growing number of Internet-connected devices used up the available supply — IPv6 provides a far larger range of addresses instead."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:5d421511', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "What is a MAC address?", "reading": "<h4>A hardware identifier</h4>\n<ul>\n<li>A <strong>MAC (Media Access Control) address</strong> is a unique identifier assigned to a device''s network interface card (NIC).</li>\n<li>It is written in <strong>hexadecimal</strong>, usually shown as six pairs of digits separated by colons or hyphens — for example, 00:1B:44:11:3A:B7.</li>\n</ul>\n<h4>Set once, and never changed</h4>\n<ul>\n<li>A MAC address is <strong>burned into the NIC by its manufacturer</strong> at the point of manufacture — it is not assigned by whichever network the device happens to join.</li>\n<li>This makes a MAC address <strong>unique to that one physical device</strong>, and it stays the same for the device''s whole lifetime, unlike an IP address.</li>\n<li>MAC addresses are used to identify devices on a LAN — for example, a switch reads the destination MAC address to work out which device on the LAN to forward data to.</li>\n</ul>", "question": "What is true about a device''s MAC address?", "options": ["It is burned into the network interface card by its manufacturer, and never changes", "It is assigned fresh by whichever network the device connects to each time", "It is chosen freely by the user the first time they set up a network connection", "It exists only for wireless devices, since wired devices use their IP address instead"]}'::jsonb, '{"answer": 0, "explain": "A MAC address is fixed permanently by the manufacturer when the network card is made — every networked device, wired or wireless, has one."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:d487babe', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "IP address vs MAC address — the exam''s favourite comparison", "reading": "<h4>Two different addresses, two different jobs</h4>\n<table>\n<tr><th>Feature</th><th>IP address</th><th>MAC address</th></tr>\n<tr><td>Assigned by</td><td>The network the device connects to</td><td>The manufacturer, burned into the NIC</td></tr>\n<tr><td>Can it change?</td><td>Yes — it can change between networks or sessions</td><td>No — it is permanent for the life of the device</td></tr>\n<tr><td>Format</td><td>Denary (IPv4) or hexadecimal (IPv6)</td><td>Hexadecimal</td></tr>\n<tr><td>Main purpose</td><td>Routing data between different networks</td><td>Identifying a specific device on a LAN</td></tr>\n</table>\n<h4>The line examiners look for</h4>\n<ul>\n<li>Say it as a contrast: an IP address is <strong>logical</strong> and can change, because the network assigns it; a MAC address is <strong>physical</strong> and permanent, because the manufacturer burns it into the hardware.</li>\n</ul>", "question": "Which address is assigned by the network a device connects to, meaning it can change?", "options": ["The IP address", "The MAC address", "Both addresses always change together at the same time", "Neither address is ever assigned to a device"]}'::jsonb, '{"answer": 0, "explain": "The IP address is assigned by the network, so it can change — the MAC address is fixed permanently by the manufacturer and never changes."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:3593a680', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "What is a standard, and why do networks need them?", "reading": "<h4>An agreed specification</h4>\n<ul>\n<li>A <strong>standard</strong> is an agreed set of rules or specifications that hardware and software are designed to follow.</li>\n</ul>\n<h4>Why they matter</h4>\n<ul>\n<li>Without standards, a network card made by one manufacturer might not be able to communicate at all with a switch or router made by a completely different manufacturer.</li>\n<li>Standards mean that hardware and software from <strong>different manufacturers can work together</strong> — a laptop, a router and a web server, all made by entirely different companies, can all communicate because they follow the same agreed standards.</li>\n</ul>", "question": "Why do computer networks rely on agreed standards?", "options": ["So hardware and software made by different manufacturers can work together successfully", "So every network in the whole world is forced to buy its hardware from one single manufacturer", "So a network''s speed automatically increases every time a new standard is published", "So governments can charge companies a licence fee before they can sell networking hardware"]}'::jsonb, '{"answer": 0, "explain": "A standard is an agreed specification. Following it means equipment from different manufacturers can still communicate and interoperate successfully."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:d340af24', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "What is a protocol?", "reading": "<h4>An agreed set of rules for communication</h4>\n<ul>\n<li>A <strong>protocol</strong> is an agreed set of rules that governs how devices communicate with each other — for example, the format the data must be sent in, and how errors are handled.</li>\n<li>Different protocols exist for different jobs on a network — sending a webpage, sending an email, and transferring a file each use different protocols.</li>\n<li>For two devices to communicate successfully, both must be using — and correctly following — the same protocol.</li>\n</ul>", "question": "Which of these best defines a protocol?", "options": ["An agreed set of rules that governs how devices communicate with each other", "A physical networking device that connects several separate computers together within one single office", "A password that must be entered before a device can join a network", "A brand name that a manufacturer gives to its own range of routers"]}'::jsonb, '{"answer": 0, "explain": "A protocol is a set of communication rules, not a physical device, a password, or a brand name."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:bbcd1390', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "TCP/IP — how data actually gets across a network", "reading": "<h4>A suite, not a single protocol</h4>\n<ul>\n<li><strong>TCP/IP</strong> is a <strong>suite (collection) of protocols</strong> that work together — it is not one single protocol.</li>\n</ul>\n<h4>TCP''s job</h4>\n<ul>\n<li><strong>TCP (Transmission Control Protocol)</strong> splits data into smaller pieces called <strong>packets</strong> before it is sent.</li>\n<li>At the receiving end, TCP reassembles the packets back into their correct order.</li>\n<li>TCP also checks whether any packets are missing or have arrived corrupted, and requests that they be resent if so.</li>\n</ul>\n<h4>IP''s job</h4>\n<ul>\n<li><strong>IP (Internet Protocol)</strong> handles addressing and routing — making sure each packet is sent to the correct IP address and finds its way across the network (or between networks) to its destination.</li>\n</ul>", "question": "Why is it inaccurate to describe TCP/IP as a single protocol?", "options": ["It''s a suite of protocols, including TCP and IP, that each do a different job", "TCP and IP are actually just two different names for the exact same one protocol", "TCP/IP isn''t a protocol of any kind — it is only a type of network cable", "IP handles email while TCP handles web pages, so they can''t be one protocol"]}'::jsonb, '{"answer": 0, "explain": "TCP/IP is a suite: TCP handles splitting data into packets and reassembling them, while IP handles addressing and routing those packets — two different jobs working together."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:ea30b557', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "Protocols for the web: HTTP, HTTPS and FTP", "reading": "<h4>HTTP and HTTPS</h4>\n<ul>\n<li><strong>HTTP (HyperText Transfer Protocol)</strong> is used to request and transfer web pages between a web server and a browser.</li>\n<li><strong>HTTPS (HTTP Secure)</strong> does the same job as HTTP, but adds <strong>encryption</strong> — so the data being transferred cannot be read even if it is intercepted. Websites that handle passwords, bank details or online payments should always use HTTPS.</li>\n</ul>\n<h4>FTP</h4>\n<ul>\n<li><strong>FTP (File Transfer Protocol)</strong> is used to transfer files between computers over a network — for example, uploading a website''s files onto a web server.</li>\n</ul>", "question": "What is the relationship between HTTP and HTTPS?", "options": ["HTTPS is HTTP with encryption added, for secure data transfer", "HTTPS and HTTP are two completely unrelated protocols with different jobs", "HTTPS completely replaced HTTP, so HTTP is no longer used by any website", "HTTPS is only used for sending email, while HTTP is only used for web pages"]}'::jsonb, '{"answer": 0, "explain": "HTTPS performs the same job as HTTP — requesting and transferring web pages — but adds encryption to protect the data being transferred."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:e200150a', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "Email protocols: SMTP, POP and IMAP", "reading": "<table>\n<tr><th>Protocol</th><th>Job</th></tr>\n<tr><td>SMTP</td><td>Sends email — from a user to their mail server, and between mail servers</td></tr>\n<tr><td>POP</td><td>Retrieves email from a server, and typically removes it from the server once downloaded</td></tr>\n<tr><td>IMAP</td><td>Retrieves email but keeps it on the server, syncing the same mailbox across multiple devices</td></tr>\n</table>\n<h4>The exam trap</h4>\n<ul>\n<li>SMTP is the only one of the three that <strong>sends</strong> email — POP and IMAP are both about <strong>retrieving</strong> email that has already arrived.</li>\n<li>POP and IMAP are easy to mix up: POP usually removes the message from the server once it has downloaded to one device, while IMAP keeps the message on the server so it stays in sync across a phone, a laptop and a tablet all checking the same account.</li>\n</ul>", "question": "A user wants the same mailbox to stay in sync when they check it from both their phone and their laptop. Which protocol suits this best?", "options": ["IMAP, because it keeps mail on the server and syncs it across every device", "POP, because it downloads a fresh copy of every message to each device it checks", "SMTP, because it is responsible for retrieving mail from a server", "FTP, because it can transfer the same file to more than one device at once"]}'::jsonb, '{"answer": 0, "explain": "IMAP keeps messages on the server and syncs the mailbox across devices, whereas POP typically downloads and removes each message from the server once."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:learn:bcd1d855', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'learn', 'mcq', 1, '{"readingTitle": "Why are networks divided into layers?", "reading": "<h4>The concept</h4>\n<ul>\n<li>A network''s protocols are organised into <strong>layers</strong>. Each layer has its own specific role and its own set of protocols, and handles one part of the overall job of getting data from one device to another.</li>\n<li>Data passes down through the layers on the sending device, across the network, and back up through the matching layers on the receiving device.</li>\n</ul>\n<h4>Benefits of using layers</h4>\n<ul>\n<li><strong>Manageable, self-contained parts:</strong> breaking a complex system into layers makes it far easier to design, understand and build than tackling the whole thing as one enormous system.</li>\n<li><strong>Independent development:</strong> a layer can be updated, redesigned or replaced without needing to change any of the other layers, as long as it still does its job in the same way.</li>\n<li><strong>Standardisation and interoperability:</strong> because each layer follows agreed standards, hardware and software made by different manufacturers can all work together, layer by layer.</li>\n<li><strong>Easier troubleshooting:</strong> if something goes wrong, engineers can test and isolate the fault to one specific layer, rather than searching through the whole system.</li>\n</ul>", "question": "What is one genuine benefit of dividing a network''s protocols into layers?", "options": ["Each layer can be developed or changed independently, without redesigning the other layers", "Every single layer must always be built and maintained by the exact same one single manufacturer", "Data no longer needs to pass through every layer at all before reaching its destination", "Layers remove the need for any hardware or software standards to ever be followed"]}'::jsonb, '{"answer": 0, "explain": "Because each layer only depends on the layers around it doing their own job correctly, it can be updated or replaced on its own without needing every other layer to change too."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:eeeea828', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mixing up IP addresses and MAC addresses — being unsure which one ''is the one that changes''.</p><p><strong>✅ The correct idea:</strong> It is the <strong>IP address</strong> that can change, since it''s assigned by whichever network the device connects to. The <strong>MAC address</strong> is fixed permanently by the manufacturer when the network card is made, and never changes for that device.</p>", "question": "Which address is assigned by the network, and can therefore change?", "options": ["The IP address", "The MAC address", "Both addresses change together every time a device connects", "Neither address is ever assigned to a device at all"]}'::jsonb, '{"answer": 0, "explain": "The network assigns the IP address, so it can change. The MAC address is fixed permanently by the manufacturer."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:510a3e71', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking SMTP is the protocol used to check an inbox and download new emails.</p><p><strong>✅ The correct idea:</strong> SMTP''s job is to <strong>send</strong> email — from a user to their mail server, and between mail servers. Retrieving email that has already arrived uses a different protocol: POP or IMAP.</p>", "question": "Which protocol is responsible for SENDING an email?", "options": ["SMTP", "POP", "IMAP", "HTTP"]}'::jsonb, '{"answer": 0, "explain": "SMTP sends email. POP and IMAP are both used to retrieve email that has already arrived on a server."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:e6ca87f1', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming POP and IMAP do exactly the same job, since they''re both used to ''get your email''.</p><p><strong>✅ The correct idea:</strong> Both retrieve email, but differently: POP typically <strong>downloads and removes</strong> the message from the server, so it only exists on the one device it was downloaded to. IMAP <strong>keeps</strong> the message on the server, syncing it across every device that checks the account.</p>", "question": "A user wants the same mailbox to stay in sync across their phone and laptop. Which protocol suits this best?", "options": ["IMAP", "POP", "SMTP", "FTP"]}'::jsonb, '{"answer": 0, "explain": "IMAP keeps mail on the server and syncs it across devices, unlike POP, which typically removes each message from the server once downloaded."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:ea30b557', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing HTTPS is a completely separate protocol from HTTP, unrelated to it.</p><p><strong>✅ The correct idea:</strong> HTTPS is simply <strong>HTTP with encryption added</strong>. It does exactly the same job — requesting and transferring web pages — but encrypts the data so it cannot be read if intercepted.</p>", "question": "What is the relationship between HTTP and HTTPS?", "options": ["HTTPS is HTTP with encryption added, for secure data transfer", "HTTPS and HTTP are two completely unrelated protocols with different jobs", "HTTPS replaced HTTP entirely, so HTTP is no longer used by any website", "HTTPS is used only for sending email, while HTTP is used only for web pages"]}'::jsonb, '{"answer": 0, "explain": "HTTPS performs HTTP''s job with encryption added — it is not a separate, unrelated protocol."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:2c074641', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that encrypting a wireless network stops the data from being intercepted in the first place.</p><p><strong>✅ The correct idea:</strong> Encryption does <strong>not</strong> stop data being intercepted — a wireless signal can still be picked up by any device in range. What encryption does is make the intercepted data <strong>unreadable</strong> without the correct key.</p>", "question": "A hacker intercepts encrypted data sent over a shop''s Wi-Fi. What is true?", "options": ["They have the data, but cannot read it without the correct key", "They cannot have intercepted the data at all, since it was encrypted", "They can read the data instantly, since encryption only hides who sent it", "Encryption prevents the Wi-Fi signal from ever reaching the hacker''s device"]}'::jsonb, '{"answer": 0, "explain": "Encryption doesn''t prevent interception — it makes the intercepted data meaningless without the decryption key."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:misc:0219cc45', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Referring to ''the TCP/IP protocol'' as if it were one single protocol.</p><p><strong>✅ The correct idea:</strong> TCP/IP is a <strong>suite</strong> — a collection of protocols working together, not one protocol. TCP handles splitting data into packets and reassembling them; IP handles addressing and routing those packets between networks.</p>", "question": "Why is it inaccurate to call TCP/IP ''a single protocol''?", "options": ["It''s a suite of protocols (including TCP and IP) that each do a different job", "TCP and IP are simply two completely different names used for the exact same one protocol", "TCP/IP is not actually a protocol of any kind, only a cable type", "IP handles email while TCP handles web pages, so they can''t be one protocol"]}'::jsonb, '{"answer": 0, "explain": "TCP/IP is a suite made up of separate protocols — TCP and IP — that each do a different job."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tips:d352d059', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tips', 'mcq', 1, '{"readingTitle": "explain — Command-word ladder: a 2-mark ''describe'' on POP vs IMAP", "reading": "<p>A typical question: <em>\"Describe the difference between how POP and IMAP handle an email once it has been retrieved.\"</em> [2 marks] The same idea, shown at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"POP and IMAP are both used to get your emails.\"</p>\n<ul>\n<li>True, but this doesn''t describe any DIFFERENCE at all — it just restates what both protocols are broadly for.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"POP deletes the email from the server.\"</p>\n<ul>\n<li>Correct about POP, but the question asked for a difference — IMAP''s contrasting behaviour is missing entirely.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"POP typically downloads an email and removes it from the server, so it only exists on that one device. IMAP retrieves the email but keeps it on the server, so it stays synced across every device that checks the account.\"</p>\n\n<p><strong>Why this matters:</strong> \"describe the difference\" questions on this topic need BOTH sides stated, ideally directly contrasted. Naming only one protocol''s behaviour, even correctly, only earns half the marks available.</p>", "question": "A student answers ''Describe the difference between POP and IMAP'' by writing only ''POP removes the email from the server''. Why does this likely score half marks?", "options": ["It only describes one side of the difference — IMAP''s contrasting behaviour is missing", "It is factually incorrect about what POP actually does to an email once it is downloaded", "It is far too long an answer for a 2-mark question to ever reward fully", "POP and IMAP cannot be compared in an exam answer, only defined separately"]}'::jsonb, '{"answer": 0, "explain": "''Describe the difference'' needs both sides — what POP does AND what IMAP does differently — not just one protocol''s behaviour on its own."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tips:92118e6e', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tips', 'mcq', 1, '{"readingTitle": "explain — Command-word ladder: a 3-mark ''explain'' on why TCP splits data into packets", "reading": "<p>A typical question: <em>\"Explain why TCP splits data into packets before sending it across a network.\"</em> [3 marks] Explain questions need a chain of reasoning, not just a fact.</p>\n\n<p><strong>❌ 0-1 marks:</strong> \"TCP splits data into packets.\"</p>\n<ul>\n<li>This just restates the question — it doesn''t explain WHY splitting into packets is useful, so there''s very little to credit.</li>\n</ul>\n\n<p><strong>⚠️ 1-2 marks:</strong> \"TCP splits data into packets so it can check whether any have gone missing.\"</p>\n<ul>\n<li>This links splitting to ONE genuine reason (checking for loss), but stops short of a full three-step chain.</li>\n</ul>\n\n<p><strong>✅ 3 marks:</strong> \"TCP splits data into smaller packets so that each one can be sent and numbered separately. This means individual packets can be checked for loss or corruption once they arrive. If a packet is missing or corrupted, only that one packet needs to be resent, rather than resending the entire file again from scratch.\"</p>\n\n<p><strong>Why this matters:</strong> \"explain why\" questions on TCP/IP are marked as a chain: mechanism → what it allows → the practical benefit. Naming the fact that TCP splits data into packets is only the first link — follow it through to why that actually helps.</p>", "question": "Why does a 3-mark ''explain'' question about TCP splitting data into packets need more than the single sentence ''TCP splits data into packets''?", "options": ["It restates the question without explaining WHY splitting the data helps at all", "TCP does not actually split data into packets, so the sentence is factually wrong", "The sentence is too short to fit inside the exam''s printed answer box", "Explain questions about TCP/IP are always levelled 6-8 mark questions"]}'::jsonb, '{"answer": 0, "explain": "An ''explain why'' answer needs a chain of reasoning — restating the fact from the question doesn''t explain the reasoning behind it."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:tips:b1df8bca', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'tips', 'mcq', 1, '{"readingTitle": "tip — The IP-vs-MAC trap: read the command word AND the address type twice", "reading": "<p>Questions that ask you to explain something about BOTH an IP address and a MAC address in the same answer are a very common trap on this topic — it''s easy to accidentally write correct facts about the wrong address.</p>\n\n<p><strong>❌ The trap:</strong> writing \"the MAC address is assigned by the network and can change\" — this sentence is completely correct, just about the wrong address. It''s actually describing an IP address. Marks are lost not because the fact is wrong, but because it''s attached to the wrong label.</p>\n\n<p><strong>✅ The reliable method:</strong> use a simple memory device before you write a single word — <strong>\"M for MAC = Manufacturer = fixed for life\"</strong> and <strong>\"I for IP = In the network''s hands = can change\"</strong>. Say which address you''re describing out loud (or underline it) before writing each sentence.</p>\n\n<p><strong>Worked example — \"explain why a device''s IP address might change, but its MAC address never will\":</strong></p>\n<ul>\n<li><strong>IP:</strong> assigned fresh by whichever network the device joins, so a new network (or reconnecting) can give it a different address.</li>\n<li><strong>MAC:</strong> burned into the network interface card by its manufacturer at production, so it stays fixed for the device''s entire life regardless of which network it joins.</li>\n</ul>", "question": "A student writes ''the MAC address is assigned by the network and can change'' in answer to an IP-vs-MAC question. What has most likely gone wrong?", "options": ["A true fact about an IP address has been attached to the wrong address''s label", "The sentence is entirely factually incorrect about both IP and MAC addresses", "MAC addresses genuinely are assigned by the network, so this is actually correct", "The student has confused a MAC address with a wireless access point"]}'::jsonb, '{"answer": 0, "explain": "The fact described — assigned by the network, can change — correctly describes an IP address, not a MAC address. The content is right; it''s attached to the wrong term."}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:fib:e12a2594', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'fib', 'fib', 1, '{"question": "_____ is the standard most commonly used for wired network connections, usually over twisted pair copper cable.", "blankOptions": {"B1": ["denary", "layers", "Ethernet", "MAC"]}}'::jsonb, '{"blanks": {"B1": "Ethernet"}}'::jsonb),
