('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:match:4ee8f925', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “SMTP”?", "options": ["An agreed set of rules or specifications that lets hardware and software from different manufacturers work together", "Lets a device connect wirelessly to a LAN through a wireless access point", "An agreed set of rules that governs how devices communicate with each other", "Sends email, from a user to their mail server and between mail servers"]}'::jsonb, '{"answer": 3, "explain": "“SMTP” means: Sends email, from a user to their mail server and between mail servers"}'::jsonb),
('computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers:match:78e9eff3', 'computer-science', 'computer-science:1-3-2-wired-and-wireless-networks-protocols-and-layers', '1.3.2 Wired and Wireless Networks, Protocols and Layers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “POP”?", "options": ["Splits data into packets, reassembles them in order, and requests any lost or corrupted packets again", "Handles the addressing and routing of packets between networks", "Retrieves email from a server and typically removes it from the server once downloaded", "The same job as HTTP, but with encryption added to protect the data in transit"]}'::jsonb, '{"answer": 2, "explain": "“POP” means: Retrieves email from a server and typically removes it from the server once downloaded"}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:exam:3cf834f0', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the type of malware that disguises itself as a legitimate, wanted program but does not copy itself onto other files.</p>", "options": ["Virus", "Worm", "Trojan", "Ransomware"], "hint": "Focus on the two facts given: disguised as something wanted, and does NOT self-replicate — only one of the four options fits both."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Trojan</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Trojan."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:exam:12eb8251', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the type of attack that floods a server with a huge number of requests so that real users cannot access the service, without stealing or changing any data.</p>", "options": ["Denial of Service (DoS)", "Data interception and theft", "SQL injection", "Social engineering"], "hint": "The question tells you the goal is stopping ACCESS, not reading or changing data — that rules out three of the four options straight away."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Denial of Service (DoS)</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Denial of Service (DoS)."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:85ea0f08', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "Which type of malware needs a user to run an infected file before it can spread to other files?", "options": ["A worm, since it copies itself and spreads automatically across an entire network without any user action", "A virus, since it attaches to a file and needs that file to be run", "A trojan, since it disguises itself as wanted software", "Ransomware, since it encrypts files as soon as it is downloaded"]}'::jsonb, '{"answer": 1, "explain": "A virus depends entirely on the user running its infected host file — that is what separates it from a worm, which spreads unaided."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:ea57bcad', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "Which statement about worms is correct?", "options": ["A worm needs the user to open an infected file before it can spread", "A worm copies itself across a network without any action from the user", "A worm disguises itself as useful software the user chooses to install", "A worm can only infect one single computer and cannot spread further"]}'::jsonb, '{"answer": 1, "explain": "A worm is self-replicating and spreads across a network entirely by itself, with no user action required."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:3dc478e4', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "What makes a trojan different from a virus or a worm?", "options": ["A trojan spreads automatically across a network with no user action", "A trojan does not copy itself onto other files or other computers", "A trojan can only affect files stored on a removable USB drive", "A trojan is not capable of stealing or damaging any data at all"]}'::jsonb, '{"answer": 1, "explain": "A trojan tricks a user into installing it by disguising itself as wanted software, but unlike a virus or worm it does not self-replicate."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:f83ffd92', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "What does ransomware do to a victim''s files?", "options": ["It permanently deletes every file stored on the computer, leaving nothing behind to recover", "It encrypts the files and demands payment for the decryption key", "It slows the computer down until the files can no longer open", "It copies the files onto the attacker''s own computer only"]}'::jsonb, '{"answer": 1, "explain": "Ransomware encrypts the victim''s files and holds the decryption key to ransom — the files still exist, but cannot be opened without paying."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:c03f7008', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of spyware?", "options": ["To secretly monitor a user''s activity and steal information such as passwords", "To flood a server with an overwhelming amount of traffic so real users cannot access it at all", "To display unwanted adverts whenever the user opens a browser", "To physically damage the storage device a computer is using"]}'::jsonb, '{"answer": 0, "explain": "Spyware is designed to go unnoticed while it secretly monitors what a user does and sends that information back to an attacker."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:5298cfbd', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "Why are people often described as ''the weakest link'' in computer security?", "options": ["Because most computers are physically weaker and more prone to hardware failure than the software running on them", "Because a person can be tricked or manipulated into bypassing strong technical security", "Because human passwords are always stored using weaker encryption than files", "Because people are legally not allowed to report a suspected cyber-attack"]}'::jsonb, '{"answer": 1, "explain": "Even the strongest technical defences are useless if an attacker can simply persuade a person to hand over access voluntarily."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:95a39df4', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "An employee receives an email that looks like it is from their bank, asking them to click a link and confirm their account password. What type of attack is this?", "options": ["Brute-force attack", "Phishing", "Denial of Service", "SQL injection"]}'::jsonb, '{"answer": 1, "explain": "A fake message impersonating a trusted organisation (the bank) to trick the victim into revealing details is a classic phishing attack."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:bea517b0', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "What is ''blagging'' (pretexting) in the context of social engineering?", "options": ["Automatically guessing thousands of possible password combinations very quickly using software", "Inventing a false scenario to persuade a victim into giving up information", "Watching over someone''s shoulder as they type in a password", "Flooding a company''s server with fake requests until it crashes"]}'::jsonb, '{"answer": 1, "explain": "Blagging (pretexting) means making up a believable false story to talk a victim into handing over information or access."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:7d6c8668', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "A website locks a user''s account for ten minutes after five incorrect password attempts in a row. Which attack is this rule specifically designed to slow down?", "options": ["Phishing", "SQL injection", "Brute-force attack", "A denial of service attack"]}'::jsonb, '{"answer": 2, "explain": "Locking an account after repeated failed logins directly targets brute-force attacks, which rely on trying combination after combination quickly."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:408fff20', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "A shopping website suddenly becomes very slow and eventually stops responding after receiving an enormous, coordinated surge of traffic from thousands of different computers at once. What is this attack most likely to be?", "options": ["A virus infection", "A distributed denial of service (DDoS) attack", "A single trojan that was secretly installed on the server by an employee", "A SQL injection attack"]}'::jsonb, '{"answer": 1, "explain": "Traffic arriving from thousands of different computers at once, aimed at overwhelming the server, is the defining feature of a DDoS attack."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:931b79bf', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "Why is using an unsecured public Wi-Fi network risky for sending personal data?", "options": ["The Wi-Fi signal automatically deletes any data sent over it", "Data sent over the network can more easily be intercepted and read by an attacker", "Unsecured networks always run at a much slower connection speed than properly secured ones", "Public Wi-Fi routers cannot connect to more than one device at a time"]}'::jsonb, '{"answer": 1, "explain": "Without encryption, data travelling across an unsecured network can be captured and read by anyone intercepting it."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:mcq:90d5e032', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'mcq', 'mcq', 1, '{"question": "What does a SQL injection attack involve?", "options": ["Overloading a server with an enormous number of simultaneous requests until it can no longer respond", "Entering malicious code into a website''s input box to manipulate its database", "Physically watching a user type their password into a system", "Sending a fake email that pretends to be from a trusted organisation"]}'::jsonb, '{"answer": 1, "explain": "SQL injection means typing malicious SQL code into an input box so the database runs the attacker''s command instead of the expected one."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:b132b0af', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "A worm needs the user to open an infected file before it can spread."}'::jsonb, '{"answer": false, "explain": "That describes a virus. A worm spreads across a network entirely by itself, without needing any action from the user."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:00ad6787', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "A trojan copies itself onto other files, spreading in the same way as a virus."}'::jsonb, '{"answer": false, "explain": "A trojan does NOT self-replicate. It relies on tricking the user into installing it by disguising itself as wanted software."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:9045e721', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "Ransomware encrypts a victim''s files rather than simply hiding or deleting them."}'::jsonb, '{"answer": true, "explain": "Correct — ransomware scrambles the files with an encryption key and demands payment for the key needed to unlock them."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:2fc918b8', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "Social engineering attacks target weaknesses in software, rather than weaknesses in people."}'::jsonb, '{"answer": false, "explain": "It''s the opposite — social engineering deliberately targets a PERSON, manipulating them, rather than exploiting a technical software flaw."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:069bca9f', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "Phishing is a type of social engineering attack."}'::jsonb, '{"answer": true, "explain": "Correct — phishing tricks a person using a fake message impersonating a trusted organisation, which makes it a form of social engineering."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:9bb34f80', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "A Denial of Service attack is designed to steal data from a server."}'::jsonb, '{"answer": false, "explain": "A DoS attack does not steal or alter any data — it floods a server so genuine users cannot access it. Stealing data is not its purpose."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:639188ca', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "A brute-force attack tries many possible passwords automatically until one works."}'::jsonb, '{"answer": true, "explain": "Correct — brute-force attacks are a purely automated, technical guessing attack against a login system."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:tf:67c2948c', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'tf', 'tf', 1, '{"question": "SQL injection involves entering malicious code into an input box to attack a database."}'::jsonb, '{"answer": true, "explain": "Correct — the attacker types SQL code into a box like a login or search field, hoping the website passes it straight into a database command."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:9be1efd7', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "What is malware, and what can it actually do?", "reading": "<h4>Malware = malicious software</h4>\n<ul>\n<li><strong>Malware</strong> is any software that has been deliberately written to damage, disrupt, or gain unauthorised access to a computer system or network.</li>\n<li>It is defined by what it was designed to DO, not by how it arrives — malware can reach a victim through an email attachment, an infected download, a fake app, or an infected USB stick.</li>\n<li>Once it is running, malware can: <strong>delete or corrupt</strong> files, <strong>lock a user out</strong> of their own data, <strong>steal</strong> personal or financial information, <strong>spy</strong> on what a user types or does, or quietly use the victim''s computer to help attack somebody else.</li>\n</ul>\n<h4>One family, several very different shapes</h4>\n<ul>\n<li>\"Malware\" is an umbrella term. A <strong>virus</strong>, a <strong>worm</strong>, a <strong>trojan</strong>, <strong>ransomware</strong> and <strong>spyware</strong> are all different shapes of malware — each one spreads in a different way and does a different job once it is running.</li>\n<li>The exam skill across this whole family is telling these shapes apart: HOW each one spreads, and WHAT it actually does to the victim.</li>\n</ul>", "question": "Which of these is the best definition of malware?", "options": ["Any fault in a computer''s hardware that causes it to run more slowly than usual over time", "Software deliberately written to damage, disrupt or gain unauthorised access to a system", "A weak password that is easy for an attacker to guess correctly", "Any file that has become too large for its storage device to hold comfortably"]}'::jsonb, '{"answer": 1, "explain": "Malware is defined by its deliberate, malicious purpose — the other options describe unrelated hardware or password issues, not malicious software."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:811304ec', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Computer viruses — how do they spread?", "reading": "<h4>A virus needs a host — and needs the user to run it</h4>\n<ul>\n<li>A <strong>virus</strong> is malware that attaches itself to a legitimate file or program (its \"host\").</li>\n<li>Crucially, a virus <strong>cannot spread on its own</strong> — it only starts spreading once a user runs (opens or executes) the infected host file, for example by opening an infected document or launching an infected program.</li>\n<li>Once run, it can copy itself into other files or programs on the same computer, and often tries to spread further when an infected file is shared, e.g. emailed to someone else or copied onto a USB stick.</li>\n<li>Because it depends on user action, avoiding suspicious downloads and attachments is a genuinely effective defence against a virus.</li>\n</ul>", "question": "What must happen before a virus can start to spread?", "options": ["A user must run (open) the infected file it is attached to", "The computer must be connected to the internet for more than an hour", "Another piece of malware must already be installed on the computer", "The computer''s antivirus software must be switched off completely"]}'::jsonb, '{"answer": 0, "explain": "A virus is inactive until the infected host file is actually run — that single action is what triggers it to start copying itself."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:3ca06774', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Worms — spreading without any help from the user", "reading": "<h4>Self-replicating, and needs no user action at all</h4>\n<ul>\n<li>A <strong>worm</strong> is malware that can copy (replicate) itself and spread across a network entirely <strong>by itself</strong>.</li>\n<li>Unlike a virus, a worm does <strong>not</strong> need a user to open an infected file, click a link, or take any action whatsoever — it can move from computer to computer on its own, often by exploiting a weakness (vulnerability) in software or in how a network is set up.</li>\n<li>Because it spreads unaided, a worm can infect huge numbers of computers extremely quickly once it is loose on a network.</li>\n</ul>\n<h4>The exam''s favourite contrast</h4>\n<ul>\n<li><strong>Virus</strong> = needs the user to run an infected file. <strong>Worm</strong> = spreads completely on its own. If a question describes malware spreading \"without the user doing anything\", it is describing a worm, not a virus.</li>\n</ul>", "question": "What makes a worm different from a virus?", "options": ["A worm only affects computers that are not connected to any network", "A worm can spread across a network by itself, without any user action", "A worm cannot copy itself onto any other computer at all", "A worm always needs a matching virus to already be present before it is able to run at all"]}'::jsonb, '{"answer": 1, "explain": "A worm is fully self-replicating and self-spreading — it needs no user action, which is exactly what separates it from a virus."}'::jsonb),
('computer-science:1-4-1-threats-to-computer-systems-and-networks:learn:3d5d4936', 'computer-science', 'computer-science:1-4-1-threats-to-computer-systems-and-networks', '1.4.1 Threats to Computer Systems and Networks', 'learn', 'mcq', 1, '{"readingTitle": "Trojans — malware in disguise", "reading": "<h4>Willingly installed, not self-replicating</h4>\n<ul>\n<li>A <strong>trojan</strong> disguises itself as legitimate, useful or wanted software — a free game, a \"helpful\" tool, a cracked version of paid software — so the victim installs it <strong>willingly</strong>, believing it is safe.</li>\n<li>Once installed, a trojan can do many things: open a hidden \"backdoor\" for an attacker, steal data, or quietly install further malware.</li>\n<li>The key exam fact: a trojan does <strong>NOT</strong> self-replicate. Unlike a virus or a worm, it does not copy itself onto other files or other computers — it relies entirely on tricking a person into installing it in the first place.</li>\n</ul>", "question": "Which statement about trojans is correct?", "options": ["A trojan copies itself onto other files completely automatically, spreading in exactly the same way as a virus does", "A trojan disguises itself as wanted software and does not copy itself onto other files", "A trojan can only run on computers that are not connected to the internet", "A trojan always encrypts a victim''s files and demands a ransom payment"]}'::jsonb, '{"answer": 1, "explain": "A trojan tricks the user into installing it by pretending to be something wanted — but unlike a virus or worm, it does not self-replicate."}'::jsonb)
